/**
 * @public
 */
export interface DataTableColumnOrderBaseProps {
    /**
     * Enables column ordering functionality in the table.
     */
    columnOrdering?: boolean;
    /**
     * Callback that is called when the column order of any column is changed.
     * It provides the changed column order along with the underlying trigger that indicates
     * if the change was triggered by a user interaction or internally.
     */
    onColumnOrderChange?: (columnOrder: string[], trigger: 'user' | 'internal') => void;
}
/**
 * @public
 */
export interface DataTableColumnOrderControlledProps extends DataTableColumnOrderBaseProps {
    /**
     * Lets you control the column order of the individual columns.
     */
    columnOrder?: string[];
    /**
     * Lets you set the initial column order of the individual columns.
     */
    defaultColumnOrder?: never;
}
/**
 * @public
 */
export interface DataTableColumnOrderUncontrolledProps extends DataTableColumnOrderBaseProps {
    /**
     * Lets you control the column order of the individual columns.
     */
    columnOrder?: never;
    /**
     * Lets you set the initial column order of the individual columns.
     */
    defaultColumnOrder?: string[];
}
/**
 * Interface defining the props on the DataTable that control the column order feature.
 * @public
 */
export type DataTableColumnOrderProps = DataTableColumnOrderControlledProps | DataTableColumnOrderUncontrolledProps;
/**
 * Extension interface to extend the tanstack table column order state.
 * @internal
 */
export interface DataTableColumnOrderOptions {
    /**
     * The initial column order.
     */
    originalColumnOrder?: string[];
    /**
     * Enables column ordering.
     */
    enableColumnOrdering?: boolean;
}
/** @internal */
export interface DataTableColumnOrderState<TColumn = unknown> {
    /**
     * The id of the currently dragged header.
     */
    draggedHeaderColumn?: TColumn;
}
/**
 * @internal
 */
export interface DataTableColumnOrderInstance<TColumn = unknown> {
    _getOrderColumnsFn: () => (columns: TColumn[]) => TColumn[];
    /**
     * Returns an array of all leaf-node columns without the builtin prefix/suffix columns.
     */
    getLeafColumnsWithoutBuiltin: () => TColumn[];
    /**
     * Sets or updates the `state.draggedHeaderId` state.
     */
    setDraggedHeaderColumn: (column?: TColumn) => void;
}
/**
 * Extension interface to extend the tanstack table header instance.
 * @internal
 */
export interface DataTableColumnOrderHeader {
    /**
     * Defines the drag and drop interaction mode for the current header.
     * - 'none': Drag and drop is disabled.
     * - 'enabled': Drag and drop is enabled along with other interactions.
     * - 'only': Drag and drop is the only interaction (no menu/sorting).
     */
    getColumnDragAndDropMode: () => 'none' | 'enabled' | 'only';
    /**
     * Whether drag and drop is disabled on the header (if a child column is dragged).
     */
    getIsDragAndDropDisabled: () => boolean;
}
/**
 * @internal
 */
export interface DataTableColumnOrderColumn {
    /**
     * Determines whether the current column can be moved to the left.
     *
     * Returns `false` if:
     * - The column is the first in the overall column order.
     * - The column is the first within its group.
     * - All columns to the left of it are pinned.
     *
     * @returns `true` if the column can be moved to the left; otherwise, `false`.
     */
    getCanMoveColumnLeft: () => boolean;
    /**
     * Determines whether the current column can be moved to the right.
     *
     * Returns `false` if:
     * - The column is the last in the overall column order.
     * - The column is the last within its group.
     * - All columns to the right of it are pinned.
     *
     * @returns `true` if the column can be moved to the right; otherwise, `false`.
     */
    getCanMoveColumnRight: () => boolean;
    /**
     * Moves the current column one position to the left and updates the table state.
     */
    moveColumnLeft: () => void;
    /**
     * Moves the current column one position to the right and updates the table state.
     */
    moveColumnRight: () => void;
}
